scwin.vCurDate;
scwin.vQryStDt;
scwin.vQryEndDt;

scwin.onpageload = function() {
    scwin.vCurDate = $c.date.getServerDateTime("yyyyMMdd");                                     // 서버를 기준으로 현재 날짜 반환
    scwin.vQryStDt = scwin.vCurDate.substr(0,6) + "01";                                         // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
    scwin.vQryEndDt = scwin.vCurDate.substr(0,6) + $c.date.getLastDateOfMonth(scwin.vCurDate);  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)

    ds_purchaseEvidence.insertRow();

    const codeOptions = [
        { grpCd : "FS402", compID : "acb_pchsItemCd" }
    ];
    $c.data.setCommonCode(codeOptions, scwin.setCommonCodeCallback);

};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {

    }, {"delay":150});
};

scwin.setCommonCodeCallback = function(){
    acb_pchsItemCd.setMaxLength(50);
    acb_pchsItemCd.addItem("선택", "", "", 0);
    acb_pchsItemCd.setSelectedIndex(0);         // 매입항목

    scwin.f_SetDefaultData();

    $c.gus.cfDisableBtnOnly([btn_save]);

};

scwin.f_SaveOpAmt = function() {
    let win_url = "/ui/ds/fs/adjm/fs_101_01_06b.xml";
    let data = {};
    let opts = {
          id : "saveOpAmtPop"
        , popupName : "운영원가 입력"
        , modal : true
        , type : "browserPopup"
        , width : 940
        , height : 490
        , title : "운영원가 입력"
    };
    $c.win.openPopup(win_url, opts, data);

};

//-------------------------------------------------------------------------
// Default Data Setting
//-------------------------------------------------------------------------
scwin.f_SetDefaultData = function () {


    ica_wrkDtSt.setValue(scwin.vQryStDt);       // 배차일자시작
    ica_wrkDtEnd.setValue(scwin.vQryEndDt);     // 배차일자종료
    ica_slipDt.setValue(scwin.vCurDate);        // 전표일자
    // cfSetIMEModeActiveObjects([ed_summary, ed_pchsDeptNm, ed_pchsClntNm]);  // IME 한글입력

    $c.gus.cfDisableObjects([btn_CalcAmt, acb_pchsItemCd, ica_slipDt, ed_summary
                           , udc_pchsDept // ,ed_pchsDeptCd, ed_pchsDeptNm, img_PopUp2
                           , udc_pchsClnt // ,ed_pchsClntNo, ed_pchsClntNm, img_PopUp3
                           , ed_spplyAmt, ed_vat
    ]);
    ica_wrkDtSt.focus();


    // ica_wrkDtSt.setValue("20200101");
    // ica_wrkDtEnd.setValue("20200131");
};

//-------------------------------------------------------------------------
// 역별철송저감금액 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveStationEachRailroadCutAmtList = async function () {
    var validateFlg =await $c.gus.cfValidate([ica_wrkDtSt, ica_wrkDtEnd]);
    if (!validateFlg) {
        return;
    }
    var cfIsAfterDateFlg = await $c.gus.cfIsAfterDate(ica_wrkDtSt.getValue(), ica_wrkDtEnd.getValue());
    if (!cfIsAfterDateFlg) {
        await $c.gus.cfAlertMsg("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
        ica_wrkDtSt.focus();
        return;
    }
    ds_searchStationEachRailroadCutAmtList.set("pchsItemCd", acb_pchsItemCd.getValue());

    // sbm_searchStationEachRailroadCutAmtList_submitdone 처리리
    var response = await $c.sbm.execute(sbm_searchStationEachRailroadCutAmtList);
    if (response.responseJSON.resultDataSet[0].Msg == "SUCC"){
        scwin.sbm_searchStationEachRailroadCutAmtList_submitdone(response);
    }
};

//-------------------------------------------------------------------------
// 세금계산서 등록 저장
//-------------------------------------------------------------------------
scwin.f_RegistTaxInvoice = async function () {	
    var ds_stationEachRailroadCutAmtList_modiFlg = ds_stationEachRailroadCutAmtList.getModifiedIndex().length;
    // Data 변경 여부 조회
    if (!ds_stationEachRailroadCutAmtList_modiFlg) {
        await $c.gus.cfAlertMsg("비용배부를 선택하십시오.");
        return;
    }
    var ds_purchaseEvidence_modiFlg = ds_purchaseEvidence.getModifiedIndex().length;
    if (!ds_purchaseEvidence_modiFlg) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["매입 정보"]);
        return;
    }
    if (ed_spplyAmt.getValue() == 0 || ed_spplyAmt.getValue().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["공급금액"]);
        ed_spplyAmt.focus();			
        return;
    }
    //if (ed_vat.getValue() == 0 || ed_vat.getValue().length == 0) {
    //	await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["부가세"]);
    //	ed_vat.focus();
    //	return;
    //}
    if (ed_summary.getValue().legth == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["비용배부"]);
        return;		
    }
    var ds_stationEachRailroadCutAmtList_nameSum_spplyAmt = scwin.f_nameSum(ds_stationEachRailroadCutAmtList, "spplyAmt");
    if (ed_spplyAmt.getValue() != ds_stationEachRailroadCutAmtList_nameSum_spplyAmt) {
        await $c.gus.cfAlertMsg("공급금액을 다시 확인하십시오.");
        ed_spplyAmt.focus();
        return;		
    }
    var ds_stationEachRailroadCutAmtList_nameSum_vat = scwin.f_nameSum(ds_stationEachRailroadCutAmtList, "vat");
    if (ed_vat.getValue() != ds_stationEachRailroadCutAmtList_nameSum_vat) {
        await $c.gus.cfAlertMsg("부가세를 다시 확인하십시오.");
        ed_vat.focus();
        return;		
    }
    var validateFlg = await $c.gus.cfValidate([acb_pchsItemCd, ed_pchsDeptCd, ica_slipDt, ed_summary, ed_pchsClntNo ]);
    if (!validateFlg) {
        return;
    }
    // 저장하시겠습니까?
    var confirmFlg = await $c.win.confirm(MSG_CM_CRM_001);
    if (confirmFlg) {  
        // 확정구분코드(계산서작성)
        ds_purchaseEvidence.setCellData(0, "dcsnClsCd", "3");
        ds_purchaseEvidence.setCellData(0, "elecAuthTrgtYn", "0"); // 전자인증여부(전자세금계산서)-미적용

        $c.sbm.execute(sbm_savetPurchaseEvidence);
    }
};

//-------------------------------------------------------------------------
// 오더 정보, 매입확정/매입증빙 정보 Data Clear
//-------------------------------------------------------------------------
scwin.f_PchsDataClear = function () {
    $c.gus.cfInitObjects(tb_dcsnData);

    ica_slipDt.setValue(scwin.vCurDate);    // 전표일자
    txt_certiNo.setValue("");               // 거래명세서번호
    ed_summary.setValue("");                // 금액합계
};

//-------------------------------------------------------------------------
// 비용배부 계산
//-------------------------------------------------------------------------
scwin.f_Calc = async function (Colid) {
    if (acb_pchsItemCd.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["원가유형"]);
        ed_spplyAmt.focus();            
        return;
    }
    if (ed_spplyAmt.getValue() == 0 || ed_spplyAmt.getValue().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["공급금액"]);
        ed_spplyAmt.focus();            
        return;
    }
    var spplyAmt    = ed_spplyAmt.getValue();
    var vat         = ed_vat.getValue();
    var pchsClntNo  = ed_pchsClntNo.getValue();
    var pchsClntNm  = ed_pchsClntNm.getValue();
    var pchsDeptCd  = ed_pchsDeptCd.getValue();
    var pchsDeptNm  = ed_pchsDeptNm.getValue();
    var pchsItemCd  = acb_pchsItemCd.getValue();
    var summary     = ed_summary.getValue();

    await scwin.f_RetrieveStationEachRailroadCutAmtList();
    acb_pchsItemCd.setValue(pchsItemCd);
    ed_spplyAmt.setValue(spplyAmt);
    ed_vat.setValue(vat);       
    ed_pchsClntNo.setValue(pchsClntNo);
    ed_pchsClntNm.setValue(pchsClntNm);
    ed_pchsDeptCd.setValue(pchsDeptCd);
    ed_pchsDeptNm.setValue(pchsDeptNm);
    ed_summary.setValue(summary);

    //if (ed_vat.getValue() == 0 || ed_vat.getValue().length == 0) {
    //  await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["부가세"]);
    //  ed_vat.focus();         
    //  return;
    //}
    /*
        2014.05.07 수정
        14.4.1일부로 철도정책이 변경됨에 따라 검수비 배부기준 변경 필요
        지선 구간의 경우 사유화차 실적 감소 예상으로 검수비 과다 배부 방지
        [변경기준] => 당월 검수비 원가 * 당월저감액비율 = 공급금액
    */
    scwin.f_CalcOrigin(Colid);
    /*
    if ("T" == ds_stationEachRailroadCutAmtList.getCellData(1, "adptGubCd")) {
        scwin.f_CalcOrigin(Colid);
    } else {
        scwin.f_CalcNew(Colid);
    }
    */
    var amt = $c.gus.cfInsertComma(parseInt(ed_spplyAmt.getValue()) + parseInt(ed_vat.getValue()));  // 금액합계
    txt_sumAmt.setValue(amt);       
};

scwin.f_CalcOrigin = function (Colid) {
    var rowCnt = ds_stationEachRailroadCutAmtList.getRowCount();
    var cutAmtSum = scwin.f_nameSum(ds_stationEachRailroadCutAmtList, "cutAmt");

    // 공급가액/부가세 계산
    var totSpplyAmt = 0;
    var totVat = 0;
    var spplyAmt = 0;
    var vat = 0;
    for (var i = 0 ; i < rowCnt ; i++) {
        if (i == (rowCnt - 1)) {
            ds_stationEachRailroadCutAmtList.setCellData(i, "spplyAmt", ed_spplyAmt.getValue() - totSpplyAmt);
            ds_stationEachRailroadCutAmtList.setCellData(i, "vat", ed_vat.getValue() - totVat);
        } else {
            //spplyAmt = Math.round((ds_stationEachRailroadCutAmtList.getCellData(i, Colid) / ds_stationEachRailroadCutAmtList.NameSum(Colid, 0, 0)) * ed_spplyAmt.getValue());
            //vat = Math.round((ds_stationEachRailroadCutAmtList.getCellData(i, Colid) / ds_stationEachRailroadCutAmtList.NameSum(Colid, 0, 0)) * ed_vat.getValue());
            //2015.01.14 출발역별저감율적용(공통코드 OP662 관리)
            //저감액비율
            //var bdRt = ds_stationEachRailroadCutAmtList.getCellData(i, "rt") / 100; 기존
            var bdRt = ds_stationEachRailroadCutAmtList.getCellData(i, "cutAmt") / cutAmtSum;
            spplyAmt = Math.round(ed_spplyAmt.getValue() * bdRt);
            vat 	 = Math.round(ed_vat.getValue() * bdRt);

            ds_stationEachRailroadCutAmtList.setCellData(i, "spplyAmt", spplyAmt);
            ds_stationEachRailroadCutAmtList.setCellData(i, "vat", vat);
            totSpplyAmt += spplyAmt;
            totVat += vat;
        }
    }
};

scwin.f_CalcNew = function (Colid) {
    // 공급가액/부가세 계산
    var totSpplyAmt = 0;
    var totVat = 0;
    var spplyAmt = 0;
    var vat = 0;
    var rowCnt = ds_stationEachRailroadCutAmtList.getRowCount();
    for (var i = 0 ; i < rowCnt ; i++) {
        if (i == rowCnt-1) {
            ds_stationEachRailroadCutAmtList.setCellData(i, "spplyAmt", ed_spplyAmt.getValue() - totSpplyAmt);
            ds_stationEachRailroadCutAmtList.setCellData(i, "vat", ed_vat.getValue() - totVat);
        } else {
            //운영원가비율(철송협회비) * (저감액 * 80%) * 저감액비율 + (운영원가(철송협회비)  - 저감액80% * 운영원가비율(철송협회비)) * 08년도 저감액 비율 * (1/지사 철송 count)
            //운영원가
            var bdSpplyAmt = ed_spplyAmt.getValue();
            var bdVat = ed_vat.getValue();

            //저감액비율
            var bdRt = ds_stationEachRailroadCutAmtList.getCellData(i, "rt") / 100;
            //운영원가비율
            var bdOpAmtRt = ds_stationEachRailroadCutAmtList.getCellData(i, "opAmtRt");
            //VAT비율
            var bdOpVatRt = ds_stationEachRailroadCutAmtList.getCellData(i, "opVatRt");
            //전년도 저감액 비율
            var bdLastRt = ds_stationEachRailroadCutAmtList.getCellData(i, "lastRt") / 100;
            //저감총액
            var bdRailroadCutAmtSum = ds_stationEachRailroadCutAmtList.getCellData(i, "railroadCutAmtSum");
            //저감총액 * 80
            var bdRailroadCutAmtSumE = bdRailroadCutAmtSum * 0.8;
            //지사철송 cnt
            var bdDptCnt = ds_stationEachRailroadCutAmtList.getCellData(i, "dptCnt");
            var bdDptStCnt = ds_stationEachRailroadCutAmtList.getCellData(i, "dptStCnt");


            //spplyAmt = Math.round((bdSpplyAmt - bdRailroadCutAmtSumE * bdOpAmtRt) * bdLastRt * Math.round(bdDptStCnt*100000/bdDptCnt)/100000);
            spplyAmt = Math.round((bdOpAmtRt * bdRailroadCutAmtSumE * bdRt)) + Math.round((bdSpplyAmt - bdRailroadCutAmtSumE * bdOpAmtRt) * bdLastRt * Math.round(bdDptStCnt*100000/bdDptCnt)/100000);
            if(bdVat > 0){
                vat = Math.round(spplyAmt * 0.1); 
            }else{
                vat = 0; 
            }
            //vat = Math.round((bdOpVatRt * bdRailroadCutAmtSumE * bdRt * 0.1) * Math.round(bdDptStCnt*100000/bdDptCnt)/100000) + Math.round((bdVat - bdRailroadCutAmtSumE * bdOpVatRt * 0.1) * bdLastRt * Math.round(bdDptStCnt*100000/bdDptCnt)/100000);
            //spplyAmt = Math.round((bdOpAmtRt * bdRailroadCutAmtSumE * bdRt + (bdSpplyAmt - bdRailroadCutAmtSumE * bdOpAmtRt) * bdLastRt) );
            //vat = Math.round((bdOpVatRt * bdRailroadCutAmtSumE * bdRt * 0.1 + (bdVat - bdRailroadCutAmtSumE * bdOpVatRt * 0.1) * bdLastRt) * (bdDptStCnt/bdDptCnt));

            ds_stationEachRailroadCutAmtList.setCellData(i, "spplyAmt", spplyAmt);
            ds_stationEachRailroadCutAmtList.setCellData(i, "vat", vat);
            totSpplyAmt += spplyAmt;
            totVat += vat;
        }
    }
};   

//-------------------------------------------------------------------------
// 엑셀 다운로드
//-------------------------------------------------------------------------	
