        return;
    } else {
        // gr_stationEachRailroadCutAmtList.SetExcelTitle(1, "value:철송 배차 내역;"  // 표시할 타이틀
        //                                                 + "font-face:'돋움체';" // 폰트
        //                                                 + "font-size:12pt;"    // 폰트 크기
        //                                                 + "font-color:black;"  // 폰트 색깔
        //                                                 + "bgcolor:#ffffff;"   // 배경 색깔
        //                                                 + "align:center;"      // 정렬
        //                                                 + "line-color:white;"  // 타이틀 부분 테두리선 색깔
        //                                                 + "line-width:0pt;"    // 타이틀 테두리선 굵기
        //                                                 + "skiprow:1;");       // 타이틀 다음 떼는 로우 수
        // cfGridToExcel(그리드ID, "엑셀 파일의 쉬트명", "엑셀 파일명", 저장 옵션);

        // cfGridToExcel(gr_stationEachRailroadCutAmtList, "철송 배차 내역", "철송 배차 내역.xls", 4 + 8 + 16);

        var argGridTotalCol = 0;
        for (var i = 0 ; i < gr_stationEachRailroadCutAmtList.getTotalCol(); i++) {
