            // , fontSize    : "12pt"
            , fontName    : "돋움체"
            , color       : "black"
            , fontWeight  : ""
            , drawBorder  : "false"
            , borderColor : ""
            , borderWidth : ""
            , wordWrap    : "true"
            , bgColor     : "#ffffff"
        }];
        const options = {
            fileName : "철송 배차 내역.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
            sheetName: "철송 배차 내역",
            type : "1",
            startRowIndex: 2,
            // removeColumns: "0,21",
            // hiddenVisible : true,
            // useSubTotal :"true", 
            // useSubTotalData  : "true",
            // oddRowBackgroundColor  : "",                        // excel파일에서 그리드 body의 홀수줄의 배경색
            // evenRowBackgroundColor : "#F5FFF5"                  // excel파일에서 그리드 body의 짝수줄의 배경색
        };
        $c.data.downloadGridViewExcel(gr_stationEachRailroadCutAmtList, options, infoArr);

    }
};

