scwin.sbm_searchStationEachRailroadCutAmtList_submitdone = async function (e) {
    // cfHideDSWaitMsg(gr_stationEachRailroadCutAmtList);

    // 총 조회건수 표시
    // cfShowTotalRows(totalRows, rowCnt);
    var rowCnt = ds_stationEachRailroadCutAmtList.getRowCount();
    txt_totalRows.setValue(rowCnt);

    scwin.f_PchsDataClear();

    if (rowCnt == 0) {
        $c.gus.cfDisableObjects([btn_CalcAmt, acb_pchsItemCd, ica_slipDt // , img_slipDt
                                , ed_summary
                                , udc_pchsDept // , ed_pchsDeptCd, ed_pchsDeptNm, img_PopUp2
                                , udc_pchsClnt // , ed_pchsClntNo, ed_pchsClntNm, img_PopUp3
                                , ed_spplyAmt, ed_vat]);
        $c.gus.cfDisableBtnOnly([btn_save]);
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);  // 해당되는 자료가 존재하지 않습니다
    } else {
        $c.gus.cfEnableObjects([btn_CalcAmt, acb_pchsItemCd, ica_slipDt // , img_slipDt
                                , ed_summary
                                , udc_pchsDept // , ed_pchsDeptCd, ed_pchsDeptNm, img_PopUp2
                                , udc_pchsClnt // , ed_pchsClntNo, ed_pchsClntNm, img_PopUp3
                                , ed_spplyAmt, ed_vat]);
        $c.gus.cfEnableBtnOnly([btn_save]);
    }
};

