scwin.f_nameSum = function(dataList, column){
    var rowCnt = dataList.getRowCount();
    var totalVal = 0;
    for (var i = 0; i < rowCnt; i++){
        var targetVal = parseInt(dataList.getCellData(i, column));
        totalVal += targetVal;
    }
    return totalVal
};

